const response = fetch('https://es.wikipedia.org/w/api.php?action=query&list=random&rnnamespace=0&rnlimit=1&format=json');
const data = await response.json();
const title = data.query.random[0].title;
const articleUrl = `https://es.wikipedia.org/wiki/${title}`;
const articleResponse = fetch(articleUrl);
const articleData = await articleResponse.text();
return articleData;
